-- Multiline showcase entry, timestamped to sit directly below agentcash-mark
INSERT INTO statuslines (slug, name, description, author, price_usd, spec, tags, installs, featured, created_at)
VALUES ('mission-control', 'Mission Control', 'Two lines of full instrumentation: model, directory and branch up top; live context bar, session cost, and rate-limit gauges below.', 'statuslines.dev', '0', '{"version":1,"powerline":true,"segments":[{"text":"{model}","fg":"#0c0a09","bg":"#fafaf9","bold":true},{"text":"{dir}{gitDirty}","fg":"#e7e5e4","bg":"#44403c"},{"text":" {gitBranch}","fg":"#a8a29e","bg":"#292524","when":"gitBranch"},{"text":"{contextBar}","fg":"#4ade80","bg":"#0c0a09","newline":true},{"text":"{contextPct} used","fg":"#86efac","bg":"#0c0a09","dim":true},{"text":"{cost} · {duration}","fg":"#fbbf24","bg":"#0c0a09"},{"text":"5h {limit5h} · 7d {limit7d}","fg":"#78716c","bg":"#0c0a09","when":"limit5h"}]}'::jsonb, ARRAY['multi-line','context','powerline']::text[], 0, true,
  COALESCE((SELECT created_at - interval '1 second' FROM statuslines WHERE slug = 'agentcash-mark'), now()))
ON CONFLICT (slug) DO UPDATE SET spec = EXCLUDED.spec, description = EXCLUDED.description;
